"use client";

import { useState, useEffect } from "react";
import { useCalendar, type CalendarEvent } from "@/hooks/use-calendar";
import { Calendar } from "@/components/ui/calendar";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { CalendarDays, Wallet, Clock, AlertCircle, ChevronRight } from "lucide-react";
import { format, isSameDay, parseISO } from "date-fns";
import { zhCN } from "date-fns/locale";

export default function CalendarPage() {
    const { events, isLoading } = useCalendar();
    const [selectedDate, setSelectedDate] = useState<Date | undefined>();
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        setSelectedDate(new Date());
    }, []);

    if (!mounted) return null;

    // Group events by date for the small indicators
    const eventsOnSelectedDate = events.filter(event =>
        selectedDate && isSameDay(parseISO(event.date), selectedDate)
    );

    // Custom calendar modifiers to show dots
    const modifiers = {
        hasEvent: (date: Date) => events.some(e => isSameDay(parseISO(e.date), date)),
        hasPremium: (date: Date) => events.some(e => e.type === 'premium' && isSameDay(parseISO(e.date), date)),
        hasExpiry: (date: Date) => events.some(e => e.type === 'expiry' && isSameDay(parseISO(e.date), date)),
    };

    const modifiersClassNames = {
        hasPremium: "has-premium",
        hasExpiry: "has-expiry",
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500 max-w-7xl mx-auto pb-12">
            <style jsx global>{`
                .has-premium {
                    background-color: #d1fae5 !important;
                    color: #047857 !important;
                    font-weight: 700 !important;
                    border: 1px solid #10b981 !important;
                }
                .has-expiry {
                    background-color: #fee2e2 !important;
                    color: #b91c1c !important;
                    font-weight: 700 !important;
                    border: 1px solid #ef4444 !important;
                }
                .rdp-months {
                    width: 100%;
                    justify-content: space-around;
                }
                .rdp-selected .rdp-day_button {
                    background-color: #059669 !important;
                    color: white !important;
                    font-weight: bold !important;
                    border-radius: 0.5rem !important;
                    box-shadow: 0 4px 6px -1px rgba(5, 150, 105, 0.4) !important;
                }
                .rdp-today .rdp-day_button {
                    background-color: #f1f5f9 !important;
                    color: #0f172a !important;
                    border: 2px solid #059669 !important;
                    font-weight: 900 !important;
                    border-radius: 0.5rem !important;
                }
            `}</style>

            <div className="flex flex-col gap-1">
                <h2 className="text-3xl font-bold tracking-tight text-slate-900">缴费与保障日历</h2>
                <p className="text-slate-500 font-medium tracking-wide">
                    为您自动推算并汇总家庭保单的每一个关键节点
                </p>
            </div>

            {/* Top Legend Bar */}
            <div className="flex flex-col md:flex-row items-center justify-between gap-4 p-4 bg-white rounded-2xl border border-slate-200 shadow-sm">
                <div className="flex flex-wrap items-center gap-6">
                    <span className="text-sm font-bold text-slate-800 flex items-center gap-2">
                        <CalendarDays className="w-4 h-4 text-emerald-600" /> 图例说明
                    </span>
                    <div className="flex items-center gap-2 text-sm text-slate-600 font-medium">
                        <div className="w-5 h-5 rounded-md bg-[#d1fae5] border border-[#10b981] flex items-center justify-center text-xs text-[#047857] font-bold">¥</div>
                        <span>续期缴费扣款</span>
                    </div>
                    <div className="flex items-center gap-2 text-sm text-slate-600 font-medium">
                        <div className="w-5 h-5 rounded-md bg-[#fee2e2] border border-[#ef4444] flex items-center justify-center text-xs text-[#b91c1c] font-bold">!</div>
                        <span>保单到期提醒</span>
                    </div>
                </div>
                <div className="flex-1 max-w-md bg-emerald-50 rounded-xl p-3 border border-emerald-100 flex items-start gap-3">
                    <div className="mt-0.5"><Clock className="w-4 h-4 text-emerald-600" /></div>
                    <div>
                        <p className="text-xs font-bold text-emerald-800 uppercase tracking-wider mb-0.5">AI 智能分析</p>
                        <p className="text-xs text-emerald-700">根据当前保单，下一次自动扣款预计在 3 月 23 日，请确保支付卡余额充足。</p>
                    </div>
                </div>
            </div>

            {/* Calendar View (Full Width) */}
            <Card className="border-slate-200 shadow-sm overflow-hidden">
                <CardContent className="p-6 overflow-x-auto">
                    <Calendar
                        mode="single"
                        selected={selectedDate}
                        onSelect={setSelectedDate}
                        locale={zhCN}
                        className="w-full min-w-[800px]"
                        modifiers={modifiers}
                        modifiersClassNames={modifiersClassNames}
                        numberOfMonths={3}
                        pagedNavigation
                        showOutsideDays={false}
                    />
                </CardContent>
            </Card>

            {/* Event List (Bottom) */}
            <Card className="border-slate-200 shadow-sm bg-slate-50/50">
                <CardHeader className="pb-4 border-b border-slate-200 bg-white rounded-t-xl">
                    <CardTitle className="text-lg flex items-center gap-2">
                        {selectedDate ? format(selectedDate, "PPP", { locale: zhCN }) : "待办事项"}
                        <Badge variant="secondary" className="bg-emerald-100 text-emerald-700 hover:bg-emerald-100 border-none">
                            {eventsOnSelectedDate.length} 项日程
                        </Badge>
                    </CardTitle>
                    <CardDescription>选定日期的保单事项清单</CardDescription>
                </CardHeader>
                <CardContent className="p-6">
                    {eventsOnSelectedDate.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {eventsOnSelectedDate.map((event) => (
                                <div
                                    key={event.id}
                                    className="group relative p-5 rounded-2xl bg-white border border-slate-200 shadow-sm hover:border-emerald-300 hover:shadow-md transition-all cursor-pointer flex items-start gap-4"
                                >
                                    <div className={`shrink-0 p-3 rounded-xl ${event.type === 'premium' ? 'bg-[#d1fae5] text-[#047857]' : 'bg-[#fee2e2] text-[#b91c1c]'}`}>
                                        {event.type === 'premium' ? <Wallet className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
                                    </div>
                                    <div className="space-y-1.5 flex-1 pr-6">
                                        <p className="font-bold text-slate-900 text-base leading-tight">{event.title}</p>
                                        <p className="text-xs text-slate-500 line-clamp-2">{event.policy_description}</p>
                                        {event.amount && (
                                            <div className="inline-flex items-center gap-1.5 px-2 py-1 bg-slate-50 rounded-md mt-1 border border-slate-100">
                                                <span className="text-[10px] font-bold text-slate-400 uppercase">金额</span>
                                                <span className="text-sm font-black text-emerald-600">¥{event.amount}</span>
                                            </div>
                                        )}
                                    </div>
                                    <ChevronRight className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-hover:text-emerald-500 transition-colors" />
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-12 text-center text-slate-400 bg-white rounded-xl border border-dashed border-slate-200">
                            <Clock className="w-12 h-12 mb-3 text-slate-200" />
                            <p className="text-base font-medium text-slate-500">该日期暂无待办事项</p>
                            <p className="text-sm mt-1">您可以选择带有颜色标记的日期查看详情</p>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuthStore } from "@/store/auth";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CardFooter,
} from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { request } from "@/lib/request";
import { ShieldCheck, Loader2 } from "lucide-react";

export default function LoginPage() {
  const [phone, setPhone] = useState("");
  const [code, setCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [countdown, setCountdown] = useState(0);
  const router = useRouter();
  const { token, setAuth } = useAuthStore();
  const [mounted, setMounted] = useState(false);

  // Fix hydration mismatch
  useEffect(() => {
    setMounted(true);
    // If the user already has a token in their local storage, redirect immediately
    if (useAuthStore.getState().token) {
      router.push("/dashboard");
    }
  }, [router]);

  // Countdown timer for SMS
  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (countdown > 0) {
      timer = setTimeout(() => setCountdown(countdown - 1), 1000);
    }
    return () => clearTimeout(timer);
  }, [countdown]);

  if (!mounted) return null; // Avoid rendering until hydration completes

  const handleSendSms = async () => {
    if (!phone || phone.length !== 11) {
      toast.error("请输入有效的 11 位手机号码");
      return;
    }

    try {
      await request.post("/auth/send-sms", { phone });
      toast.success("验证码已发送，请注意查收");
      setCountdown(60); // Start 60s countdown
    } catch (error: any) {
      // Axios error handling to get backend detail message if available
      const errorMsg = error.response?.data?.detail || "发送失败，请稍后再试";
      toast.error(errorMsg);
      console.error(error);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!phone || phone.length !== 11) {
      toast.error("请输入有效的 11 位手机号码");
      return;
    }
    if (!code || code.length !== 6) {
      toast.error("请输入 6 位短信验证码");
      return;
    }

    setLoading(true);
    try {
      // Direct call to FastAPI login backend (proxied via Next.js rewrites)
      const res = await request.post("/auth/login", {
        phone: phone,
        code: code,
      });

      if (res.data.access_token) {
        setAuth(res.data.access_token, phone);
        toast.success("验证成功", {
          description: "正在进入家庭保单总控中心...",
        });
        setTimeout(() => {
          router.push("/dashboard");
        }, 1000);
      }
    } catch (error: any) {
      const errorMsg = error.response?.data?.detail || "验证码错误或已过期";
      toast.error("登录异常", {
        description: errorMsg,
      });
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-zinc-50 dark:bg-zinc-950 p-4">
      <Card className="w-full max-w-sm shadow-xl border-zinc-200 dark:border-zinc-800">
        <CardHeader className="space-y-2 pb-6 text-center">
          <div className="flex justify-center mb-2">
            <div className="p-3 bg-zinc-900 dark:bg-zinc-100 rounded-full text-white dark:text-black">
              <ShieldCheck className="w-8 h-8" />
            </div>
          </div>
          <CardTitle className="text-2xl font-bold tracking-tight">
            家庭保单管家
          </CardTitle>
          <CardDescription className="text-zinc-500">
            仅限受邀家庭主理人登录访问
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="phone">主理人手机号</Label>
              <Input
                id="phone"
                type="tel"
                placeholder="请输入 11 位手机号码"
                required
                value={phone}
                onChange={(e) => setPhone(e.target.value)}
                maxLength={11}
                className="h-11"
                disabled={loading}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="code">短信验证码</Label>
              <div className="flex gap-2">
                <Input
                  id="code"
                  type="text"
                  placeholder="请输入 6 位验证码"
                  required
                  maxLength={6}
                  value={code}
                  onChange={(e) => setCode(e.target.value)}
                  className="h-11"
                  disabled={loading}
                />
                <Button
                  type="button"
                  variant="outline"
                  className="h-11 w-[120px] shrink-0"
                  disabled={countdown > 0 || loading || phone.length !== 11}
                  onClick={handleSendSms}
                >
                  {countdown > 0 ? `${countdown}s 后重发` : "获取验证码"}
                </Button>
              </div>
            </div>

            <Button
              type="submit"
              className="w-full h-11 text-base font-medium mt-2"
              disabled={loading}
            >
              {loading ? (
                <>
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                  验证中...
                </>
              ) : (
                "安全登录"
              )}
            </Button>
          </form>
        </CardContent>
        <CardFooter className="flex justify-center border-t py-4 text-xs text-zinc-500">
          受明道云 HAP V3 企业级数据安全协议保护
        </CardFooter>
      </Card>
    </div>
  );
}

"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { Home, Users, Settings, LogOut, FileText, CalendarDays, Bot } from "lucide-react";
import { cn } from "@/lib/utils";
import { useAuthStore } from "@/store/auth";

const navItems = [
    { name: "保单金库", href: "/dashboard", icon: Home },
    { name: "家庭图谱", href: "/dashboard/members", icon: Users },
    { name: "缴费日历", href: "/dashboard/calendar", icon: CalendarDays },
    { name: "智能理赔问答", href: "/dashboard/chat", icon: Bot },
];

export function Sidebar() {
    const pathname = usePathname();
    const { logout } = useAuthStore();

    return (
        <div className="flex h-full w-64 flex-col border-r border-slate-200 bg-white">
            <div className="p-6">
                <h2 className="text-xl font-bold tracking-tighter text-slate-800">
                    家庭保单管家
                </h2>
                <p className="text-xs text-slate-500 mt-1">Intelligent Hub</p>
            </div>

            <div className="flex-1 overflow-auto py-4">
                <nav className="grid gap-1 px-4">
                    {navItems.map((item, index) => {
                        const Icon = item.icon;
                        const isActive = pathname === item.href;

                        return (
                            <Link
                                key={index}
                                href={item.href}
                                className={cn(
                                    "flex items-center gap-3 rounded-xl px-3 py-2.5 text-sm font-medium transition-all",
                                    isActive
                                        ? "bg-emerald-50 text-emerald-700 font-semibold"
                                        : "text-slate-500 hover:bg-slate-50 hover:text-slate-900"
                                )}
                            >
                                <Icon className={cn("h-4 w-4", isActive ? "text-emerald-500" : "")} />
                                {item.name}
                            </Link>
                        );
                    })}
                </nav>
            </div>

            <div className="p-4 border-t border-slate-100">
                <button
                    onClick={() => {
                        logout();
                        window.location.href = "/";
                    }}
                    className="flex w-full items-center gap-3 rounded-xl px-3 py-2 text-sm font-medium text-slate-500 hover:bg-red-50 hover:text-red-600 transition-colors"
                >
                    <LogOut className="h-4 w-4" />
                    安全退出
                </button>
            </div>
        </div>
    );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Loader2, AlertCircle, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";
import { request } from "@/lib/request";
import { FamilyMember } from "@/hooks/use-family";

interface MergeIdentitiesModalProps {
    isOpen: boolean;
    onClose: () => void;
    selectedMembers: FamilyMember[];
    onMergeComplete: () => void;
}

export function MergeIdentitiesModal({ isOpen, onClose, selectedMembers, onMergeComplete }: MergeIdentitiesModalProps) {
    const [masterId, setMasterId] = useState<string>("");
    const [isSubmitting, setIsSubmitting] = useState(false);

    // Auto-select the first member whenever the modal opens or selections change
    useEffect(() => {
        if (isOpen && selectedMembers.length > 0) {
            // Check if current masterId is still valid, if not, pick the first
            if (!selectedMembers.find(m => m.id === masterId)) {
                setMasterId(selectedMembers[0].id);
            }
        }
    }, [isOpen, selectedMembers, masterId]);

    const handleMerge = async () => {
        if (!masterId) return;

        const subsidiaryIds = selectedMembers
            .map(m => m.id)
            .filter(id => id !== masterId);

        if (subsidiaryIds.length === 0) {
            toast.error("请至少选择两个需要合并的身份");
            return;
        }

        try {
            setIsSubmitting(true);
            toast.loading("正在执行图谱融合协议...", { id: "merge-toast" });

            const res = await request.post("/family/merge", {
                master_id: masterId,
                subsidiary_ids: subsidiaryIds
            });

            if (res.data?.success) {
                toast.success(`成功合并 ${res.data.merged_names.length} 个身份名下的 ${res.data.migrated_policies} 份保单`, { id: "merge-toast" });
                onMergeComplete();
            } else {
                throw new Error("API returned failure");
            }
        } catch (error) {
            console.error("Merge failed:", error);
            toast.error("实体融合失败，请稍后再试", { id: "merge-toast" });
        } finally {
            setIsSubmitting(false);
        }
    };

    if (selectedMembers.length < 2) return null;

    return (
        <Dialog open={isOpen} onOpenChange={(open) => !isSubmitting && !open && onClose()}>
            <DialogContent className="sm:max-w-[550px] p-0 overflow-hidden border-0 shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] rounded-3xl">
                {/* Decorative header background */}
                <div className="bg-gradient-to-br from-emerald-500 to-teal-600 p-8 text-white relative overflow-hidden">
                    <div className="absolute -right-10 -top-10 w-40 h-40 bg-white/10 rounded-full blur-2xl"></div>
                    <div className="absolute right-20 bottom-10 w-20 h-20 bg-emerald-300/20 rounded-full blur-xl"></div>

                    <DialogHeader className="relative z-10">
                        <DialogTitle className="text-2xl font-bold tracking-tight text-white mb-2">
                            数据归并向导
                        </DialogTitle>
                        <DialogDescription className="text-emerald-50 text-sm font-medium leading-relaxed">
                            您正准备将 <strong>{selectedMembers.length}</strong> 个冗余身份实体合并。<br />
                            请先在下方指定一个<strong className="text-white px-1">终极基准身份</strong>。其余被选中的实体将携名下所有资产划归并在系统中被永久清理。此操作不可逆，请谨慎判断。
                        </DialogDescription>
                    </DialogHeader>
                </div>

                <div className="p-6">
                    <div className="space-y-3 max-h-[40vh] overflow-y-auto px-1 custom-scrollbar">
                        {selectedMembers.map((member) => {
                            const isMaster = masterId === member.id;
                            return (
                                <div
                                    key={member.id}
                                    onClick={() => !isSubmitting && setMasterId(member.id)}
                                    className={`flex justify-between items-center p-4 rounded-2xl cursor-pointer transition-all duration-300 transform outline-none focus:outline-none ${isMaster
                                        ? "bg-emerald-50 border-[2px] border-emerald-500 shadow-[0_0_20px_rgba(16,185,129,0.1)] scale-[1.02]"
                                        : "bg-slate-50 border-2 border-slate-200 border-dashed hover:border-emerald-300 hover:bg-emerald-50/30 opacity-70 hover:opacity-100"
                                        }`}
                                >
                                    <div className="flex items-center gap-4">
                                        <Avatar className={`h-11 w-11 border-2 transition-all ${isMaster ? "border-emerald-300 shadow-sm" : "border-slate-200"}`}>
                                            <AvatarFallback className={`font-bold text-sm ${isMaster
                                                ? "bg-gradient-to-br from-emerald-400 to-emerald-600 text-white"
                                                : "bg-slate-200 text-slate-500"
                                                }`}>
                                                {member.name.charAt(0)}
                                            </AvatarFallback>
                                        </Avatar>
                                        <div>
                                            <div className={`font-bold tracking-wide transition-colors ${isMaster ? 'text-emerald-950 text-base' : 'text-slate-700'}`}>
                                                {member.name}
                                            </div>
                                            <div className={`text-xs font-medium transition-colors ${isMaster ? 'text-emerald-600' : 'text-slate-400'}`}>
                                                图谱序列号: <span className="font-mono">{member.id.substring(0, 8)}...</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* Status Indicator */}
                                    {isMaster ? (
                                        <div className="flex flex-col items-end gap-1 animate-in fade-in zoom-in duration-300">
                                            <div className="bg-emerald-500 text-white rounded-full p-1.5 shadow-sm">
                                                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"></polyline></svg>
                                            </div>
                                            <span className="text-[10px] font-bold text-emerald-600 tracking-wider">基准真身</span>
                                        </div>
                                    ) : (
                                        <div className="text-[11px] font-bold text-slate-400 bg-slate-200/50 px-3 py-1.5 rounded-full tracking-wide">
                                            将被吸收合流
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                </div>

                <div className="bg-slate-50 px-6 py-4 border-t border-slate-100 flex items-center justify-between mt-2">
                    <div className="flex flex-col">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-0.5">资产转移评估</span>
                        <span className="text-sm font-semibold text-slate-700">将有 <strong className="text-rose-500 mx-1">{selectedMembers.length - 1}</strong> 个身份的数据汇入主身</span>
                    </div>
                    <div className="flex gap-3">
                        <Button
                            variant="ghost"
                            onClick={onClose}
                            disabled={isSubmitting}
                            className="font-semibold text-slate-500 hover:text-slate-700 rounded-xl px-5 transition-colors"
                        >
